code_string = '''from qiskit import transpile

def run_and_analyze(circuit, aer_sim, graph):
    def objective(params):
        binds = [{circuit.parameters[0]: [params[0]], circuit.parameters[1]: [params[1]]}]
        job = aer_sim.run(circuit, parameter_binds=binds)
        counts = job.result().get_counts()
        total_shots = sum(counts.values())
        expectation = 0.0
        for state, count in counts.items():
            bitstring = state[::-1]
            exp = compute_expectation({bitstring: count}, graph)
            expectation += exp * (count / total_shots)
        return -expectation

    initial_params = [0.5] * circuit.num_parameters
    result = scipy.optimize.minimize(objective, initial_params, method='L-BFGS-B')

    binds = [{circuit.parameters[0]: [result.x[0]], circuit.parameters[1]: [result.x[1]]}]
    job = aer_sim.run(circuit, parameter_binds=binds)
    counts = job.result().get_counts()

    top_two = sorted(counts.keys(), key=lambda x: counts[x], reverse=True)[:2]
    return [s[::-1] for s in top_two]'''
